// Anmeldedaten normalisieren + validieren
const body = $input.first().json.body || $input.first().json;

const vorname = (body.vorname || body.Vorname || '').trim();
const nachname = (body.nachname || body.Nachname || '').trim();
const schuelerName = (vorname && nachname) ? `${vorname} ${nachname}` : (body.name || body.Name || body.schuelerName || '');

let telefon = (body.telefon || body.phone || body.Telefon || body.Handy || '').toString();
const email = (body.email || body.Email || '').trim();
const klasse = body.klasse || body.Klasse || body.fuehrerscheinKlasse || 'B';
const geburtsdatum = body.geburtsdatum || body.Geburtsdatum || null;
const adresse = body.adresse || body.Adresse || '';
const anmerkungen = body.anmerkungen || body.Anmerkungen || body.nachricht || '';
const wunschTermin = body.wunschTermin || body.wunsch_termin || '';

// Telefonnummer bereinigen
telefon = telefon.replace(/[\s\-\/\(\)]/g, '');
if (telefon && !telefon.startsWith('+')) {
  telefon = '+49' + telefon.replace(/^0/, '');
}

return [{
  json: {
    vorname,
    nachname,
    schuelerName,
    telefon,
    email,
    klasse,
    geburtsdatum,
    adresse,
    anmerkungen,
    wunschTermin,
    anmeldeDatum: new Date().toISOString(),
    hatEmail: email.length > 0 && email.includes('@'),
    hatTelefon: telefon.length > 5
  }
}];

// Supabase returns an array; extract the created record and merge with upstream data
const upstream = $('Anmeldung normalisieren').first().json;
const created = $input.first().json;
const record = Array.isArray(created) ? created[0] : created;

return [{
  json: {
    ...upstream,
    schuelerId: record.id,
    schuelerName: upstream.schuelerName || `${upstream.vorname} ${upstream.nachname}`
  }
}];

